import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  dispatchAppToast,
  CatalogTableSkeleton,
  CatalogListShell,
  ErpDataListGrid,
  ErpListHeaderFilters,
  LinListFilterField,
  loadErpListTableConfig,
  saveErpListTableConfig,
  LinListTableConfigModal,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { ktService } from '../../services/kt/ktService';
import type { PurchaseInvoiceDto } from '../../services/kt/models';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  formatProcessingLevelFromOptions,
  resolveProcessingLevelSelectOptions,
} from '../../utils/voucherProcessingLevelOptions';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import { VoucherPrintModal, VoucherPostedLedgerModal } from '../voucher';
import { VoucherListToolbar } from '../voucher-list';
import { useVoucherListSelection } from '../../hooks/useVoucherListSelection';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../utils/voucherListRowActions';
import { getPurchaseInvoiceConfig } from '../../features/kt/purchase-invoice/shared/config/purchaseInvoiceConfig';
import erp from '../../styles/erpPage.module.css';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import { purchaseInvoiceTestIdPrefix } from './purchaseInvoiceTestId';

const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;

function listFilterScopeForInvoiceType(invoiceType: string): string {
  if (invoiceType === 'DirectPurchase') return LIST_FILTER_SCOPE.phieuNhapMuaXt;
  if (invoiceType === 'Service') return LIST_FILTER_SCOPE.hoaDonMuaDv;
  return LIST_FILTER_SCOPE.phieuNhapMua;
}

function isRowSelectable(row: PurchaseInvoiceDto): boolean {
  return row.status === 'Draft';
}

export interface PurchaseInvoiceListProps {
  title: string;
  /** Inner shell title (default: `Danh sách {title}`). */
  listTitle?: string;
  icon: string;
  invoiceType: string;
  listPath: string;
  createPath: string;
  detailPath: (id: string) => string;
  /** Init-data formName for list toolbar permissions (default shared PNM create form). */
  createInitFormName?: string;
}

export const PurchaseInvoiceList: React.FC<PurchaseInvoiceListProps> = ({
  title,
  listTitle: listTitleProp,
  icon,
  invoiceType,
  listPath,
  createPath,
  detailPath,
  createInitFormName = 'create-purchase-invoice',
}) => {
  const listTitle = listTitleProp ?? `Danh sách ${title}`;
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const listScope = listFilterScopeForInvoiceType(invoiceType);
  const testIdPrefix = purchaseInvoiceTestIdPrefix(invoiceType);
  const beCfg = getPurchaseInvoiceConfig(invoiceType, listPath, title);

  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData('purchase-invoice-list');
  const {
    canCreate,
    canApprove,
    canUpdate,
    canPrint,
    canViewLedger: canViewLedgerPerm,
  } = useVoucherListActions(createInitFormName);

  const levelOptions = useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );

  const processingLevelFilterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...levelOptions],
    [levelOptions],
  );

  const formatProcessingLabel = (level: string | undefined) =>
    formatProcessingLevelFromOptions(level, processingLevelOptions);

  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(listScope);

  const [items, setItems] = useState<PurchaseInvoiceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<VoucherListPageSize>(PAGE_SIZE);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(testIdPrefix),
  );

  const { showTableLoading } = useVoucherListTableBusy(loading);

  const selection = useVoucherListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable,
  });

  const activeRow = selection.activeRow;

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow
    ? canEditFromListRow(activeRow, canUpdate)
    : false;
  const canViewLedgerActive = activeRow
    ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm)
    : false;
  const canPrintActive = Boolean(activeRow) && canPrint;

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as VoucherListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return undefined;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getPurchaseInvoices({
        fromDate,
        toDate,
        processingLevel: processingLevel || undefined,
        invoiceType,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải danh sách'),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, fromDate, toDate, processingLevel, page, pageSize, invoiceType, reloadKey, dispatch]);

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      await ktService.batchUpdatePurchaseInvoiceProcessingLevel({
        ids: selection.selectedIdList,
        processingLevel: newLevel,
      });
      dispatchAppToast(dispatch, { message: 'Phê duyệt thành công', type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const navigateToRow = (id: string, startInEditMode?: boolean) => {
    navigate(detailPath(id), {
      state: startInEditMode ? { startInEditMode: true } : undefined,
    });
  };

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(testIdPrefix, next);
  };

  const filters = (
    <ErpListHeaderFilters testIdPrefix={testIdPrefix} filterCols={2} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${testIdPrefix}-field-dateRange`}>
        <DateRangeFilter
          label="Thời gian"
          fullWidth
          testId={`${testIdPrefix}-date-range`}
          fromDate={fromDate}
          toDate={toDate}
          preset={datePreset}
          onChange={(v: DateRangeValue) => {
            applyDateRange(v.fromDate, v.toDate, v.preset);
            resetPage();
          }}
        />
      </LinListFilterField>
      <LinListFilterField testId={`${testIdPrefix}-field-processingLevel`}>
        <Select
          label="Mức xử lý"
          value={processingLevel}
          onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
          options={processingLevelFilterOptions}
          fullWidth
        />
      </LinListFilterField>
    </ErpListHeaderFilters>
  );

  return (
    <div
      className={`${erp.page} ${erp.catalogListPage} ${erp.voucherListPage}`}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}>
            <i className={`fas ${icon}`} /> {title}
          </h1>
        </div>
      </div>

      <VoucherListToolbar
        testIdPrefix={testIdPrefix}
        onRefresh={refresh}
        canApprove={canApprove}
        approveDisabled={selection.selectedCount === 0}
        onApprove={() => setShowApproveModal(true)}
        canViewLedger={canViewLedgerActive}
        onViewLedger={() => setShowLedgerModal(true)}
        canPrint={canPrintActive}
        onPrint={() => setShowPrintModal(true)}
        canView={canViewActive}
        onView={() => activeRow && navigateToRow(activeRow.id)}
        canEdit={canEditActive}
        onEdit={() => activeRow && navigateToRow(activeRow.id, true)}
        canCreate={canCreate}
        onCreate={() => navigate(createPath)}
        onEditConfig={() => setShowConfigModal(true)}
      />

      {selection.selectedCount > 0 && (
        <div className={erp.batchBar} data-testid={`${testIdPrefix}-batch-bar`}>
          <span>Đã chọn {selection.selectedCount}</span>
          <button
            type="button"
            className={erp.batchBarLink}
            data-testid={`${testIdPrefix}-batch-clear`}
            onClick={selection.clearSelection}
          >
            Bỏ chọn tất cả
          </button>
        </div>
      )}

      <CatalogListShell
        testIdPrefix={testIdPrefix}
        title={listTitle}
        showTableLoading={showTableLoading}
        filters={filters}
        footer={!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        )}
      >
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${testIdPrefix}-table-skeleton`}
          />
        ) : items.length === 0 ? (
          <div className={erp.empty}>Không có dữ liệu</div>
        ) : (
          <ErpDataListGrid
            testIdPrefix={testIdPrefix}
            rows={items}
            page={page}
            pageSize={pageSize}
            selection={selection}
            isRowSelectable={isRowSelectable}
            getRowId={r => r.id}
            tableConfig={{ ...tableConfig, resizable: false }}
            onRowDoubleClick={row => navigateToRow(row.id)}
            headerCells={(
              <>
                <th>Số HĐ</th>
                <th>Ngày</th>
                <th>NCC</th>
                <th className={erp.colAmount}>Tổng tiền</th>
                <th>Mức xử lý</th>
              </>
            )}
            renderRow={r => (
              <>
                <td>
                  <code>{r.code}</code>
                </td>
                <td>{formatDateLocal(r.invoiceDate)}</td>
                <td>{r.supplierName ?? '—'}</td>
                <td className={erp.colAmount}>{formatVnd(r.totalAmount)}</td>
                <td data-testid={`${testIdPrefix}-row-${r.id}-processing-level`}>
                  {formatProcessingLabel(r.processingLevel)}
                </td>
              </>
            )}
          />
        )}
      </CatalogListShell>

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={String(levelOptions[0]?.value ?? '3')}
        levelOptions={levelOptions}
        onConfirm={handleBatchApproveConfirm}
        saving={approving}
        testIdPrefix={testIdPrefix}
      />

      {activeRow && (
        <>
          <VoucherPrintModal
            isOpen={showPrintModal}
            onClose={() => setShowPrintModal(false)}
            voucherTitle={`${title} — ${activeRow.code}`}
            onPrint={handlePrintConfirm}
            printing={printing}
            testIdPrefix={testIdPrefix}
          />
          <VoucherPostedLedgerModal
            isOpen={showLedgerModal}
            onClose={() => setShowLedgerModal(false)}
            voucherTitle={`${title} — ${activeRow.code}`}
            testIdPrefix={testIdPrefix}
            fetchPostedLedger={() => beCfg.getPostedLedger(activeRow.id)}
            fetchPostingStatus={() => beCfg.getPostingStatus(activeRow.id)}
          />
        </>
      )}

      <LinListTableConfigModal
        isOpen={showConfigModal}
        onClose={() => setShowConfigModal(false)}
        testIdPrefix={testIdPrefix}
        config={tableConfig}
        onSave={handleSaveTableConfig}
      />
    </div>
  );
};
